const input = $('When Executed by Another Workflow').first().json || {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function toArray(value) {
  if (Array.isArray(value)) return value;
  const text = toText(value);
  if (!text) return [];
  try {
    const parsed = JSON.parse(text);
    return Array.isArray(parsed) ? parsed : [];
  } catch (error) {
    return text.split(',').map((item) => item.trim()).filter(Boolean);
  }
}

function normalizeFields(rawFields) {
  const fallback = ['id', 'name', 'released', 'archived', 'releaseDate', 'startDate', 'description', 'overdue'];
  const values = toArray(rawFields)
    .map((value) => toText(value))
    .filter(Boolean);
  return values.length > 0 ? [...new Set(values)] : fallback;
}

function normalizeFilters(rawFilters) {
  return toArray(rawFilters)
    .map((item) => {
      if (!item || typeof item !== 'object' || Array.isArray(item)) return null;
      const field = toText(item.field || item.path || '');
      const operator = toText(item.operator || item.op || 'eq').toLowerCase();
      const value = Object.prototype.hasOwnProperty.call(item, 'value') ? item.value : '';
      if (!field) return null;
      return { field, operator, value };
    })
    .filter(Boolean);
}

function normalizeLimit(rawLimit) {
  const value = Number.parseInt(toText(rawLimit || ''), 10);
  if (!Number.isFinite(value)) return 50;
  if (value <= 0) return 0;
  return Math.min(value, 200);
}

const jiraBaseUrl = toText(input.jiraBaseUrl || 'https://atlassiansuite.mservice.com.vn:8443').replace(/\/+$/, '');
const projectKey = toText(input.projectKey || '');
const projectId = toText(input.projectId || '');
const projectRef = projectKey || projectId;
const query = toText(input.query || '');
const filters = normalizeFilters(input.filters);
const fields = normalizeFields(input.fields);
const limit = normalizeLimit(input.limit);
const sortBy = toText(input.sortBy || 'releaseDate');
const sortDirection = toText(input.sortDirection || 'desc').toLowerCase() === 'asc' ? 'asc' : 'desc';
const requestUrl = projectRef ? jiraBaseUrl + '/rest/api/2/project/' + encodeURIComponent(projectRef) + '/versions' : '';
const errorMessage = projectRef ? '' : 'projectKey hoặc projectId là bắt buộc.';

return {
  jiraBaseUrl,
  projectKey,
  projectId,
  projectRef,
  query,
  filters,
  fields,
  limit,
  sortBy,
  sortDirection,
  requestUrl,
  valid: Boolean(projectRef),
  errorMessage,
};

const request = $('Normalize Version Query Request').first().json || {};
const response = $('Fetch Project Versions').first().json || {};

function toText(value) {
  if (typeof value === 'string') return value.trim();
  if (value == null) return '';
  return String(value).trim();
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function getByPath(source, path) {
  const parts = toText(path).split('.').filter(Boolean);
  let current = source;
  for (const part of parts) {
    if (!current || typeof current !== 'object' || !(part in current)) return undefined;
    current = current[part];
  }
  return current;
}

function toComparable(value) {
  if (typeof value === 'number') return value;
  if (typeof value === 'boolean') return value;
  const text = toText(value);
  if (!text) return '';
  const numeric = Number(text);
  if (Number.isFinite(numeric) && text === String(numeric)) return numeric;
  const millis = Date.parse(text);
  if (!Number.isNaN(millis)) return millis;
  return text.toLowerCase();
}

function matchFilter(version, filter) {
  const actual = getByPath(version, filter.field);
  const operator = toText(filter.operator || 'eq').toLowerCase();
  const expected = filter.value;

  if (operator === 'exists') {
    return actual !== undefined && actual !== null && toText(actual) !== '';
  }

  if (operator === 'contains') {
    return toText(actual).toLowerCase().includes(toText(expected).toLowerCase());
  }

  if (operator === 'in') {
    const values = Array.isArray(expected) ? expected : String(expected ?? '').split(',').map((item) => item.trim()).filter(Boolean);
    return values.map((item) => toText(item).toLowerCase()).includes(toText(actual).toLowerCase());
  }

  const left = toComparable(actual);
  const right = toComparable(expected);

  if (operator === 'neq') return left !== right;
  if (operator === 'gt') return left > right;
  if (operator === 'gte') return left >= right;
  if (operator === 'lt') return left < right;
  if (operator === 'lte') return left <= right;
  return left === right;
}

function pickFields(source, fields) {
  const output = {};
  for (const field of fields) {
    const value = getByPath(source, field);
    if (value === undefined) continue;

    const parts = field.split('.').filter(Boolean);
    let cursor = output;
    for (let i = 0; i < parts.length; i += 1) {
      const part = parts[i];
      if (i === parts.length - 1) {
        cursor[part] = value;
      } else {
        cursor[part] = cursor[part] && typeof cursor[part] === 'object' && !Array.isArray(cursor[part]) ? cursor[part] : {};
        cursor = cursor[part];
      }
    }
  }
  return output;
}

if (!request.valid) {
  return {
    toolName: 'jiraProjectVersionsQuery',
    success: false,
    projectRef: toText(request.projectRef || ''),
    totalFetched: 0,
    totalMatched: 0,
    returnedCount: 0,
    query: toText(request.query || ''),
    filters: asArray(request.filters),
    selectedFields: asArray(request.fields),
    versions: [],
    errorMessage: toText(request.errorMessage || 'Invalid request.'),
  };
}

const statusCode = Number(response.statusCode || 200);
const body = Array.isArray(response.body) ? response.body : (Array.isArray(response) ? response : []);
const transportError = toText(response.error?.message || response.error?.description || response.message || '');

if (statusCode >= 400 || !Array.isArray(body)) {
  return {
    toolName: 'jiraProjectVersionsQuery',
    success: false,
    projectRef: toText(request.projectRef || ''),
    totalFetched: 0,
    totalMatched: 0,
    returnedCount: 0,
    query: toText(request.query || ''),
    filters: asArray(request.filters),
    selectedFields: asArray(request.fields),
    versions: [],
    errorMessage: transportError || ('Không lấy được versions từ Jira (HTTP ' + statusCode + ').'),
  };
}

const queryText = toText(request.query || '').toLowerCase();
const filters = asArray(request.filters);
const selectedFields = asArray(request.fields);
const totalFetched = body.length;

let matched = body.filter((version) => {
  if (!version || typeof version !== 'object') return false;

  const queryOk = !queryText || [version.name, version.description, version.id, version.releaseDate, version.startDate]
    .map((value) => toText(value).toLowerCase())
    .some((value) => value.includes(queryText));
  if (!queryOk) return false;

  return filters.every((filter) => matchFilter(version, filter));
});

const totalMatched = matched.length;
const sortBy = toText(request.sortBy || '');
const sortDirection = toText(request.sortDirection || 'desc') === 'asc' ? 1 : -1;
if (sortBy) {
  matched = matched.slice().sort((left, right) => {
    const leftValue = toComparable(getByPath(left, sortBy));
    const rightValue = toComparable(getByPath(right, sortBy));
    if (leftValue === rightValue) return 0;
    return leftValue > rightValue ? sortDirection : -sortDirection;
  });
}

const limit = Number(request.limit || 0);
if (limit > 0) {
  matched = matched.slice(0, limit);
}

const versions = matched.map((version) => pickFields(version, selectedFields));

return {
  toolName: 'jiraProjectVersionsQuery',
  success: true,
  projectRef: toText(request.projectRef || ''),
  totalFetched,
  totalMatched,
  returnedCount: versions.length,
  query: toText(request.query || ''),
  filters,
  selectedFields,
  versions,
  versionIds: versions.map((version) => toText(version.id || '')).filter(Boolean),
  versionNames: versions.map((version) => toText(version.name || '')).filter(Boolean),
  errorMessage: '',
};
